fun main() {
    // ---- Lists (ordered, allows duplicates) ----
    // Immutable list
    val numbers = listOf(1, 2, 3, 4, 5)
    println("Numbers: $numbers")
    println("First: ${numbers.first()}")
    println("Last: ${numbers.last()}")
    println("Size: ${numbers.size}")
    println("Contains 3? ${numbers.contains(3)}")
    println("Element at index 2: ${numbers[2]}")
    println("Element at index 2 (safe): ${numbers.getOrNull(2)}")

    // Mutable list
    val mutableNumbers = mutableListOf(1, 2, 3)
    mutableNumbers.add(4)
    mutableNumbers.addAll(listOf(5, 6))
    mutableNumbers.remove(3)
    mutableNumbers[0] = 10
    println("Mutable numbers: $mutableNumbers")

    // ---- Maps (key-value pairs) ----
    // Immutable map
    val userMap = mapOf(
        "Alice" to 25,
        "Bob" to 30,
        "Charlie" to 35
    )
    println("User map: $userMap")
    println("Alice's age: ${userMap["Alice"]}")
    println("Dave's age: ${userMap["Dave"] ?: "Unknown"}")
    println("Keys: ${userMap.keys}")
    println("Values: ${userMap.values}")
    println("Contains Alice? ${userMap.containsKey("Alice")}")
    println("Contains age 30? ${userMap.containsValue(30)}")

    // Mutable map
    val mutableMap = mutableMapOf("A" to 1, "B" to 2)
    mutableMap["C"] = 3
    mutableMap.put("D", 4)
    mutableMap.remove("B")
    println("Mutable map: $mutableMap")

    // ---- Sets (unordered, unique) ----
    // Immutable set
    val uniqueNumbers = setOf(1, 2, 3, 3, 4, 4, 5)
    println("Unique numbers: $uniqueNumbers")  // Duplicates removed
    println("Size: ${uniqueNumbers.size}")
    println("Contains 3? ${uniqueNumbers.contains(3)}")

    // Mutable set
    val mutableSet = mutableSetOf(1, 2, 3)
    mutableSet.add(4)
    mutableSet.addAll(setOf(5, 6))
    mutableSet.remove(3)
    println("Mutable set: $mutableSet")

    // ---- Collection operations ----
    val names = listOf("Alice", "Bob", "Charlie", "Diana", "Eve")

    // Filter
    val longNames = names.filter { it.length > 4 }
    println("Long names: $longNames")

    // Map
    val nameLengths = names.map { it.length }
    println("Name lengths: $nameLengths")

    // Sort
    val sortedNames = names.sorted()
    println("Sorted names: $sortedNames")

    val sortedDescending = names.sortedDescending()
    println("Sorted descending: $sortedDescending")

    // Reverse
    val reversed = names.reversed()
    println("Reversed: $reversed")

    // ---- Working with maps ----
    val map = mapOf("a" to 1, "b" to 2, "c" to 3)

    // Iterate over map
    for ((key, value) in map) {
        println("$key -> $value")
    }

    // Filter map
    val filteredMap = map.filter { it.value > 1 }
    println("Filtered map: $filteredMap")

    // Map keys
    val keys = map.keys
    println("Keys: $keys")

    // Map values
    val values = map.values
    println("Values: $values")

    // ---- Converting between collections ----
    val listToSet = listOf(1, 2, 3, 3, 4).toSet()
    println("List to set: $listToSet")

    val setToList = setOf(1, 2, 3).toList()
    println("Set to list: $setToList")

    // ---- Empty collections ----
    val emptyList = emptyList<Int>()
    val emptyMap = emptyMap<String, Int>()
    val emptySet = emptySet<Int>()
    println("Empty list: $emptyList")
}

