phase3.solution:
data class Person(val name: String, val age: Int)

fun main() {
    val people = listOf(
        Person("Alice", 25),
        Person("Bob", 30),
        Person("Charlie", 35),
        Person("Diana", 28),
        Person("Eve", 40)
    )

    // List
    println("People: $people")

    // Map
    val nameToAge = people.associate { it.name to it.age }
    println("Name to age: $nameToAge")

    // Set
    val ages = people.map { it.age }.toSet()
    println("Unique ages: $ages")

    // Filter
    val over30 = people.filter { it.age > 30 }
    println("Over 30: $over30")

    // Map to names
    val names = over30.map { it.name }
    println("Names over 30: $names")
}
